import { 菩薩坐身, 上臂常勢, 前臂 } from './pusa.js';
import { 寶燈 } from '../bujian/sanmaya.js';
import { 臂釧, 腕釧 } from '../bujian/index.js';
export const 金剛燈 = (bi) => 菩薩坐身(bi, {
    髻: '天髻',
    冠: '無',
    嚴先: true,
    臂(bi, 筆) {
        const { M, Qk, S, 骨, 衣, 細, 陰, 陽 } = 筆;
        骨(() => { 上臂常勢(筆, -1, 40.0); 上臂常勢(筆, 1, 40.0); });
        骨(() => 陽(() => 前臂(bi, 筆, [-13.7, 40.1], [-5.8, 41.2], { 寬根: 2.5, 寬梢: 1.9, 弓: 0.4, 肘帽: true })));
        骨(() => 陰(() => 前臂(bi, 筆, [13.7, 40.1], [5.8, 41.2], { 寬根: 2.5, 寬梢: 1.9, 弓: -0.4, 肘帽: true })));
        // 燈器先落（盞足高擎，焰出其上）
        寶燈(bi, 0, 38.6, 0.95);
        // 兩掌捧足
        衣(() => {
            for (const d of [-1, 1]) {
                M(d * 5.2, 40.6);
                Qk(d * 3.7, 41.5, d * 2.1, 40.9);
                S();
                M(d * 4.9, 41.3);
                Qk(d * 3.7, 42.0, d * 2.5, 41.5);
                S();
                細(() => {
                    for (const t of [0, 1, 2]) {
                        M(d * (4.8 - t * 0.95), 40.35 - t * 0.12);
                        Qk(d * (4.5 - t * 0.95), 40.0 - t * 0.12, d * (4.1 - t * 0.95), 39.85 - t * 0.12);
                        S();
                    }
                });
            }
        });
        // 嚴
        臂釧(bi, -1, 12.1, 14.5, 33.4);
        臂釧(bi, 1, 12.1, 14.5, 33.4);
        細(() => {
            腕釧(bi, [[-6.8, 39.9, -6.1, 40.8, -6.8, 41.9], [-5.9, 39.7, -5.2, 40.6, -5.9, 41.7]], [-6.1, 40.7]);
            腕釧(bi, [[6.8, 39.9, 6.1, 40.8, 6.8, 41.9], [5.9, 39.7, 5.2, 40.6, 5.9, 41.7]], [6.1, 40.7]);
        });
    },
});
